var a=3.14159;function f(t,r){return t+r}function m(t){return`Hello, ${t}!`}var o=function(t,r,e){return Math.min(Math.max(t,r),e)};var n=function(t,r,e){return String(e||" ").repeat(Math.max(0,r-t.length))+t};var i=function(t){return/^[^@]+@[^@]+$/.test(t)};var p=function(t){return t.toUpperCase()};var u=function(t){return[...new Set(t)]};console.log(m("world"),f(1,a),o(5,0,10),n("x",5),i("a@b"),p("hi"),u([1,2,2]));
